import React from 'react'
import {useState} from 'react'

function App() {
  const [data, formData] = useState({});
  const [arr, setArr] = useState([]);

  function handleChange(e)
  {
    formData({...data,[e.target.name]:e.target.value})

  }

  function addTask(e)
  {
    e.preventDefault();
    setArr([...arr,data])

  }

  function resetUI()
  {
    formData({});
    setArr([]);

  }

  return (
    <>
    <form>
      <input type="text" onChange={(e)=>handleChange(e)} name="username" placeholder='Enter your name...' />
      <input type="email" onChange={(e)=>handleChange(e)} name="email" placeholder="Enter your email..." />
      <br />
      <button type="submit" onClick={(e)=>addTask(e)}>Submit</button>
      <button type="reset" onClick={(e)=>resetUI(e)}>Reset</button>
    </form>

    <table >
      <thead>
        <tr>
          <th>Name</th>
          <th>Email</th>
        </tr>
      </thead>
      <tbody>
        {arr.map((obj,i)=>
        {
          return(
          <tr key={i}>
            <td>{obj.username}</td>
            <td>{obj.email}</td>
          </tr>
          )

        })}
      </tbody>
    </table>
    </>
  )
}

export default App